import React, { useState } from "react";

const moods = [
  { label: "Happy", emoji: "😊", color: "bg-yellow-400", text: "text-yellow-900" },
  { label: "Anxious", emoji: "😰", color: "bg-blue-400", text: "text-blue-900" },
  { label: "Tired", emoji: "😴", color: "bg-purple-400", text: "text-purple-900" },
  { label: "Focused", emoji: "🎯", color: "bg-green-400", text: "text-green-900" },
  { label: "Sad", emoji: "😢", color: "bg-gray-400", text: "text-gray-900" },
  { label: "Excited", emoji: "🚀", color: "bg-orange-400", text: "text-orange-900" },
];

export default function App() {
  const [selectedMood, setSelectedMood] = useState(null);
  const [plan, setPlan] = useState("");
  const [loading, setLoading] = useState(false);

  const generatePlan = async () => {
    if (!selectedMood) return;
    setLoading(true);
    setPlan("");

    try {
      const response = await fetch("https://api.openai.com/v1/chat/completions", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${process.env.REACT_APP_OPENAI_API_KEY}`,
        },
        body: JSON.stringify({
          model: "gpt-3.5-turbo",
          max_tokens: 1024,
          messages: [
            {
              role: "user",
              content: `I'm feeling ${selectedMood.label} today. Give me a short, friendly personalized day plan with 4 sections: Morning, Afternoon, Evening, and a Motivational Quote. Keep it practical and uplifting. Format each section with an emoji and a 1-2 sentence suggestion.`,
            },
          ],
        }),
      });

      const data = await response.json();
      setPlan(data.choices[0].message.content);
    } catch (error) {
      setPlan("Something went wrong. Please check your API key and try again.");
    }

    setLoading(false);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-6">
      <h1 className="text-4xl font-bold text-gray-800 mb-2">MoodCast</h1>
      <p className="text-gray-500 mb-10">How are you feeling today?</p>

      <div className="grid grid-cols-3 gap-4 mb-10">
        {moods.map((mood) => (
          <button
            key={mood.label}
            onClick={() => { setSelectedMood(mood); setPlan(""); }}
            className={`${mood.color} ${mood.text} rounded-2xl p-6 flex flex-col items-center shadow-md hover:scale-105 transition-transform duration-200 ${
              selectedMood?.label === mood.label ? "ring-4 ring-offset-2 ring-gray-800" : ""
            }`}
          >
            <span className="text-4xl mb-2">{mood.emoji}</span>
            <span className="font-semibold text-lg">{mood.label}</span>
          </button>
        ))}
      </div>

      {selectedMood && (
        <div className="bg-white rounded-2xl shadow-lg p-6 w-full max-w-md text-center">
          <p className="text-gray-600 text-lg">You selected</p>
          <p className="text-3xl font-bold mt-1">
            {selectedMood.emoji} {selectedMood.label}
          </p>
          <button
            onClick={generatePlan}
            disabled={loading}
            className="mt-6 bg-gray-800 text-white px-8 py-3 rounded-xl font-semibold hover:bg-gray-700 transition-colors disabled:opacity-50"
          >
            {loading ? "Generating..." : "Generate My Day Plan ✨"}
          </button>
        </div>
      )}

      {plan && (
        <div className="bg-white rounded-2xl shadow-lg p-6 w-full max-w-md mt-6">
          <h2 className="text-xl font-bold text-gray-800 mb-4">Your Day Plan</h2>
          <p className="text-gray-700 whitespace-pre-wrap leading-relaxed">{plan}</p>
        </div>
      )}
    </div>
  );
}
